import os
from cryptography.fernet import Fernet

# Load encryption key from config
def load_encryption_key():
    return os.environ.get('ENCRYPTION_KEY')

# Encrypt credit card number
def encrypt_credit_card(card_number):
    key = load_encryption_key()
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(card_number.encode())
    return encrypted_card

# Decrypt credit card number
def decrypt_credit_card(encrypted_card):
    key = load_encryption_key()
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card